// Filepath: /frontend/src/utils/taskUtils.ts

import { Channel, Game, CreateTaskRequest } from '@/types/task';

export function generateTaskNameAndDescription(data: Partial<CreateTaskRequest>, channels: Channel[], games: Game[]): { name: string; description: string } {
  const name = generateTaskName(data);
  const description = generateTaskDescription(data, channels, games);
  return { name, description };
}

function generateTaskName(data: Partial<CreateTaskRequest>): string {
  const parts = [];

  // Add channels
  if (data.channel_ids?.length) {
    parts.push(`${data.channel_ids.length} channel${data.channel_ids.length > 1 ? 's' : ''}`);
  }

  // Add games
  if (data.game_ids?.length) {
    parts.push(`${data.game_ids.length} game${data.game_ids.length > 1 ? 's' : ''}`);
  }

  // Add schedule info
  const schedule = data.schedule_type === 'interval'
    ? `Every ${(parseInt(data.schedule_value || '3600') / 3600).toFixed(1)}h`
    : data.schedule_type === 'cron' ? 'Custom schedule' : 'Manual';

  // Combine parts
  const baseText = parts.length > 0
    ? `${parts.join(' + ')} Task`
    : 'Custom Task';

  return `${baseText} (${schedule})`;
}

function generateTaskDescription(data: Partial<CreateTaskRequest>, channels: Channel[], games: Game[]): string {
  const parts: string[] = [];

  // Add channels
  if (data.channel_ids?.length) {
    const channelNames = data.channel_ids
      .map(id => channels.find(c => c.id === id)?.display_name || 'Unknown channel')
      .join(', ');
    parts.push(`Channels: ${channelNames}`);
  }

  // Add games
  if (data.game_ids?.length) {
    const gameNames = data.game_ids
      .map(id => games.find(g => g.id === id)?.name || 'Unknown game')
      .join(', ');
    parts.push(`Games: ${gameNames}`);
  }

  // Add schedule
  const schedule = data.schedule_type === 'interval'
    ? `Runs every ${(parseInt(data.schedule_value || '3600') / 3600).toFixed(1)} hours`
    : data.schedule_type === 'cron'
    ? 'Runs on custom schedule'
    : 'Manual execution';
  parts.push(schedule);

  // Add conditions
  if (data.conditions && Object.keys(data.conditions).length > 0) {
    const conditions = [];
    if (data.conditions.minFollowers) conditions.push(`Min followers: ${data.conditions.minFollowers}`);
    if (data.conditions.minViews) conditions.push(`Min views: ${data.conditions.minViews}`);
    if (data.conditions.minDuration) conditions.push(`Min duration: ${data.conditions.minDuration}m`);
    if (data.conditions.languages?.length) conditions.push(`Languages: ${data.conditions.languages.join(', ')}`);
    if (conditions.length) parts.push(`Conditions: ${conditions.join(', ')}`);
  }

  // Add restrictions
  if (data.restrictions && Object.keys(data.restrictions).length > 0) {
    const restrictions = [];
    if (data.restrictions.maxStoragePerChannel) {
      restrictions.push(`Max storage per channel: ${data.restrictions.maxStoragePerChannel}GB`);
    }
    if (data.restrictions.maxTotalStorage) {
      restrictions.push(`Max total storage: ${data.restrictions.maxTotalStorage}GB`);
    }
    if (restrictions.length) parts.push(`Restrictions: ${restrictions.join(', ')}`);
  }

  return parts.join('\n');
}

