import axios from 'axios';
import type { Channel, Game, Task } from '@/types';
import type { SystemSettings, StorageStats } from '@/types/settings';
import type {
  ChannelRecommendation,
  DiscoveryFeedResponse,
  DiscoveryPreferences,
  DiscoveryStats,
  GameRecommendation,
  RisingChannel,
  StreamPremiereEvent,
  TrackPremiereResponse,
  TrendingCategory,
  UpdatePreferencesResponse
} from '@/types/discovery';
import {
  CreateTaskRequest,
  TaskDetails,
  TaskProgress,
  TaskStorage,
  UpdateTaskRequest
} from "@/types/task";

class ApiClient {
  private static instance: ApiClient;
  private baseURL = 'http://localhost:3001/api';
  private authURL = 'http://localhost:3001/auth';

  private constructor() {
    // Add request interceptor for auth token
    axios.interceptors.request.use(
      (config) => {
        const token = localStorage.getItem('auth_token');
        if (token) {
          config.headers.Authorization = `Bearer ${token}`;
        }
        return config;
      },
      (error) => {
        return Promise.reject(error);
      }
    );

    // Add response interceptor for error handling
    axios.interceptors.response.use(
      (response) => response,
      (error) => {
        if (error.response?.status === 401) {
          localStorage.removeItem('auth_token');
          window.location.href = '/login';
        }
        // Extract and throw the error message
        if (error.response?.data?.error) {
          throw new Error(error.response.data.error);
        }
        if (error.response?.data?.details) {
          const details = error.response.data.details;
          const messages = details.map((detail: any) => detail.message);
          throw new Error(messages.join(', '));
        }
        throw error;
      }
    );
  }


